      out.write("\n");
      out.write("<script>\n");
      out.write("    (function () {\n");
      out.write("        // ГўВ”ВЂГўВ”ВЂ Theme persistence ГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂ\n");
      out.write("        var savedTheme = localStorage.getItem('theme');\n");
      out.write("        if (savedTheme) {\n");
      out.write("            document.documentElement.setAttribute('data-theme', savedTheme);\n");
      out.write("            document.body.setAttribute('data-theme', savedTheme);\n");
      out.write("        }\n");
      out.write("\n");
      out.write("        // ГўВ”ВЂГўВ”ВЂ Custom cursor ГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂ\n");
      out.write("        var dot = document.getElementById('cursorDot');\n");
      out.write("        var outline = document.getElementById('cursorOutline');\n");
      out.write("        if (dot && outline) {\n");
      out.write("            document.addEventListener('mousemove', function (e) {\n");
      out.write("                dot.style.left = e.clientX + 'px';\n");
      out.write("                dot.style.top = e.clientY + 'px';\n");
      out.write("                outline.style.left = e.clientX + 'px';\n");
      out.write("                outline.style.top = e.clientY + 'px';\n");
      out.write("            });\n");
      out.write("            document.addEventListener('mousedown', function () {\n");
      out.write("                dot.style.transform = 'translate(-50%,-50%) scale(1.8)';\n");
      out.write("                outline.style.transform = 'translate(-50%,-50%) scale(0.8)';\n");
      out.write("            });\n");
      out.write("            document.addEventListener('mouseup', function () {\n");
      out.write("                dot.style.transform = 'translate(-50%,-50%) scale(1)';\n");
      out.write("                outline.style.transform = 'translate(-50%,-50%) scale(1)';\n");
      out.write("            });\n");
      out.write("\n");
      out.write("            // Hover scaling effect on buttons and links\n");
      out.write("            var addHoverEffects = function() {\n");
      out.write("                var interactives = document.querySelectorAll('a, button, .btn, .nav-link, .voyastra-logo, input, select');\n");
      out.write("                interactives.forEach(function(el) {\n");
      out.write("                    if(el.dataset.cursorBound) return;\n");
      out.write("                    el.dataset.cursorBound = \"true\";\n");
      out.write("                    el.addEventListener('mouseenter', function() {\n");
      out.write("                        outline.style.transform = 'translate(-50%,-50%) scale(1.5)';\n");
      out.write("                        outline.style.backgroundColor = 'rgba(212, 165, 116, 0.15)'; \n");
      out.write("                        outline.style.borderColor = 'transparent';\n");
      out.write("                    });\n");
      out.write("                    el.addEventListener('mouseleave', function() {\n");
      out.write("                        outline.style.transform = 'translate(-50%,-50%) scale(1)';\n");
      out.write("                        outline.style.backgroundColor = 'transparent';\n");
      out.write("                        outline.style.borderColor = 'var(--color-accent)';\n");
      out.write("                    });\n");
      out.write("                });\n");
      out.write("            };\n");
      out.write("            \n");
      out.write("            // Run initially and observe DOM for dynamically added elements\n");
      out.write("            addHoverEffects();\n");
      out.write("            var observer = new MutationObserver(function(mutations) {\n");
      out.write("                if(mutations.length) addHoverEffects();\n");
      out.write("            });\n");
      out.write("            observer.observe(document.body, { childList: true, subtree: true });\n");
      out.write("        }\n");
      out.write("\n");
      out.write("        // ГўВ”ВЂГўВ”ВЂ Scroll progress line ГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂ\n");
      out.write("        var prog = document.getElementById('scrollProgress');\n");
      out.write("        if (prog) {\n");
      out.write("            window.addEventListener('scroll', function () {\n");
      out.write("                var pct = (window.scrollY / (document.body.scrollHeight - window.innerHeight)) * 100;\n");
      out.write("                prog.style.height = Math.min(pct, 100) + '%';\n");
      out.write("            }, { passive: true });\n");
      out.write("        }\n");
      out.write("\n");
      out.write("        // ГўВ”ВЂГўВ”ВЂ Auto-cycling background slides ГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂ\n");
      out.write("        var slides = document.querySelectorAll('.bg-slide');\n");
      out.write("        if (slides.length > 1) {\n");
      out.write("            var currentSlide = 0;\n");
      out.write("            setInterval(function () {\n");
      out.write("                slides[currentSlide].classList.remove('active');\n");
      out.write("                currentSlide = (currentSlide + 1) % slides.length;\n");
      out.write("                slides[currentSlide].classList.add('active');\n");
      out.write("            }, 5000);\n");
      out.write("        }\n");
      out.write("\n");
      out.write("        // ГўВ”ВЂГўВ”ВЂ Scroll-fade observer ГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂ\n");
      out.write("        document.addEventListener('DOMContentLoaded', function () {\n");
      out.write("            var fades = document.querySelectorAll('.scroll-fade');\n");
      out.write("            if (fades.length && 'IntersectionObserver' in window) {\n");
      out.write("                var obs = new IntersectionObserver(function (entries) {\n");
      out.write("                    entries.forEach(function (entry) {\n");
      out.write("                        if (entry.isIntersecting) { entry.target.classList.add('visible'); }\n");
      out.write("                    });\n");
      out.write("                }, { threshold: 0.1 });\n");
      out.write("                fades.forEach(function (el) { obs.observe(el); });\n");
      out.write("            }\n");
      out.write("\n");
      out.write("            // ГўВ”ВЂГўВ”ВЂ Theme toggle wiring ГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂГўВ”ВЂ\n");
      out.write("            var toggle = document.getElementById('themeToggle');\n");
      out.write("            if (toggle) {\n");
