      out.write("                    document.documentElement.setAttribute('data-theme', next);\n");
      out.write("                    document.body.setAttribute('data-theme', next);\n");
      out.write("                    localStorage.setItem('theme', next);\n");
      out.write("                });\n");
      out.write("            }\n");
      out.write("        });\n");
      out.write("    })();\n");
      out.write("</script>\n");
