      out.write("document.addEventListener('DOMContentLoaded', () => {\n");
      out.write("    // Primary check: use Java server-side session (most reliable)\n");
      out.write("    if (window.javaSession && window.javaSession.userId && window.javaSession.userId.length > 0) {\n");
      out.write("        if (window.javaSession.role === 'admin') {\n");
      out.write("            document.getElementById('adminAccessDenied').style.display = 'none';\n");
      out.write("            document.getElementById('adminDashboardLayout').style.display = 'flex';\n");
      out.write("            setTimeout(() => showToast('Welcome back, ' + (window.javaSession.name || 'Admin') + '.', 'success'), 800);\n");
      out.write("            initAdminDashboard();\n");
      out.write("        } else {\n");
      out.write("            document.getElementById('adminAccessDenied').style.display = 'flex';\n");
      out.write("        }\n");
      out.write("        return;\n");
      out.write("    }\n");
      out.write("    // Fallback: if no Java session found, redirect to login\n");
      out.write("    window.location.href = 'login?redirect=admin-dashboard.jsp';\n");
      out.write("});\n");
      out.write("\n");
      out.write("/* =========================================================\n");
      out.write("   UI CORE: CONFIRMATION & BULK ACTIONS\n");
