      out.write("window.pendingConfirmCallback = null;\n");
      out.write("function advancedConfirm(message, callback) {\n");
      out.write("    document.getElementById('confirmMessage').innerText = message;\n");
      out.write("    window.pendingConfirmCallback = callback;\n");
      out.write("    document.getElementById('confirmModal').classList.add('active');\n");
      out.write("}\n");
      out.write("function closeConfirmModal() {\n");
      out.write("    document.getElementById('confirmModal').classList.remove('active');\n");
      out.write("    window.pendingConfirmCallback = null;\n");
      out.write("}\n");
      out.write("document.getElementById('confirmActionBtn').addEventListener('click', () => {\n");
      out.write("    if(window.pendingConfirmCallback) window.pendingConfirmCallback();\n");
      out.write("    closeConfirmModal();\n");
      out.write("});\n");
      out.write("\n");
      out.write("let bulkSelectedIds = [];\n");
      out.write("let currentBulkContext = ''; // 'plans', 'dests', 'reviews', 'content'\n");
      out.write("\n");
      out.write("function toggleBulkItem(id, context, checkboxElem) {\n");
      out.write("    if (currentBulkContext !== context) {\n");
      out.write("        bulkSelectedIds = []; \n");
      out.write("        document.querySelectorAll('.checkbox-custom').forEach(cb => cb.checked = false);\n");
      out.write("        checkboxElem.checked = true;\n");
      out.write("        currentBulkContext = context;\n");
      out.write("    }\n");
      out.write("    \n");
      out.write("    if (checkboxElem.checked) {\n");
      out.write("        if(!bulkSelectedIds.includes(id)) bulkSelectedIds.push(id);\n");
      out.write("    } else {\n");
      out.write("        bulkSelectedIds = bulkSelectedIds.filter(i => i !== id);\n");
      out.write("    }\n");
      out.write("    updateBulkActionBar();\n");
      out.write("}\n");
      out.write("\n");
      out.write("function toggleAllBulk(context, masterCheckbox) {\n");
      out.write("    currentBulkContext = context;\n");
      out.write("    const isChecked = masterCheckbox.checked;\n");
      out.write("    bulkSelectedIds = [];\n");
      out.write("    \n");
      out.write("    const checkboxes = document.querySelectorAll(`[data-bulk-context=\"${context}\"]`);\n");
      out.write("    checkboxes.forEach(cb => {\n");
      out.write("        cb.checked = isChecked;\n");
      out.write("        if(isChecked) bulkSelectedIds.push(parseInt(cb.value));\n");
      out.write("    });\n");
      out.write("    updateBulkActionBar();\n");
      out.write("}\n");
      out.write("\n");
      out.write("function updateBulkActionBar() {\n");
      out.write("    const bar = document.getElementById('bulkActionBar');\n");
      out.write("    if (bulkSelectedIds.length > 0) {\n");
      out.write("        document.getElementById('bulkCountTxt').innerText = bulkSelectedIds.length;\n");
      out.write("        bar.classList.add('visible');\n");
      out.write("    } else {\n");
      out.write("        bar.classList.remove('visible');\n");
      out.write("        currentBulkContext = '';\n");
      out.write("    }\n");
      out.write("}\n");
      out.write("\n");
      out.write("function executeBulkAction() {\n");
      out.write("    const action = document.getElementById('bulkActionSelect').value;\n");
      out.write("    if (!action) return;\n");
      out.write("    \n");
      out.write("    if (action === 'delete') {\n");
      out.write("        advancedConfirm(`Are you sure you want to delete ${bulkSelectedIds.length} item(s)?`, () => {\n");
      out.write("            if (currentBulkContext === 'plans') {\n");
      out.write("                savePlans(getPlans().filter(p => !bulkSelectedIds.includes(p.id)));\n");
      out.write("                loadPlans();\n");
      out.write("            } else if (currentBulkContext === 'dests') {\n");
      out.write("                saveDests(getDests().filter(d => !bulkSelectedIds.includes(d.id)));\n");
      out.write("                loadDests();\n");
      out.write("            } else if (currentBulkContext === 'reviews') {\n");
      out.write("                saveReviews(getReviews().filter(r => !bulkSelectedIds.includes(r.id)));\n");
      out.write("                loadReviews();\n");
      out.write("            } else if (currentBulkContext === 'content') {\n");
      out.write("                saveContent(getContent().filter(c => !bulkSelectedIds.includes(c.id)));\n");
      out.write("                loadContent();\n");
      out.write("            }\n");
      out.write("            VoyastraToast.show(`${bulkSelectedIds.length} items deleted permanently.`, 'warning');\n");
      out.write("            bulkSelectedIds = [];\n");
      out.write("            updateBulkActionBar();\n");
      out.write("            document.getElementById('bulkActionSelect').value = '';\n");
      out.write("        });\n");
      out.write("    }\n");
      out.write("}\n");
