      out.write("\n");
      out.write("function renderActivitiesTable() {\n");
      out.write("    const query = (document.getElementById('searchActivities')?.value || '').toLowerCase();\n");
      out.write("    const tbody = document.getElementById('activitiesTableBody');\n");
      out.write("    if (!tbody) return;\n");
      out.write("\n");
      out.write("    let filtered = [...allActivities];\n");
      out.write("    if (query) {\n");
      out.write("        filtered = filtered.filter(a => \n");
      out.write("            a.name.toLowerCase().includes(query) || \n");
      out.write("            a.destinationId.toString().includes(query)\n");
      out.write("        );\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    if (filtered.length === 0) {\n");
      out.write("        tbody.innerHTML = '<tr><td colspan=\"6\" style=\"text-align:center; padding: 30px; color:#888;\">No activities found.</td></tr>';\n");
      out.write("        return;\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    tbody.innerHTML = filtered.map(a => `\n");
