      out.write("            <td><span class=\"result-badge\" style=\"background:var(--color-primary);\">${a.destinationId}</span></td>\n");
      out.write("            <td class=\"font-bold text-primary\">в‚№${a.price}</td>\n");
      out.write("            <td>в­ђ ${a.rating} <span style=\"font-size:0.7rem; color:var(--text-muted)\">(${a.reviewsCount})</span></td>\n");
      out.write("            <td style=\"text-align: right;\">\n");
      out.write("                <button type=\"button\" class=\"action-btn btn-edit\" onclick=\"editActivity(${a.id})\">Edit</button>\n");
      out.write("                <button type=\"button\" class=\"action-btn btn-delete\" onclick=\"deleteActivity(${a.id})\">Delete</button>\n");
      out.write("            </td>\n");
      out.write("        </tr>\n");
      out.write("    `).join('');\n");
      out.write("}\n");
      out.write("\n");
      out.write("function openActivityModal(mode='add', id=null) {\n");
      out.write("    const form = document.getElementById('activityForm');\n");
      out.write("    const title = document.getElementById('activityModalTitle');\n");
      out.write("    const extra = document.getElementById('activityExtraInfo');\n");
      out.write("    const destSelect = document.getElementById('activityDestId');\n");
      out.write("    \n");
      out.write("    form.reset();\n");
      out.write("    document.getElementById('activityId').value = '';\n");
      out.write("    document.getElementById('activityAction').value = 'add';\n");
      out.write("    document.getElementById('activityImagePreview').style.display = 'none';\n");
      out.write("    extra.style.display = 'none';\n");
      out.write("\n");
      out.write("    // Populate Destinations\n");
      out.write("    const dests = getDests(); // From localStorage or global state\n");
      out.write("    destSelect.innerHTML = dests.map(d => `<option value=\"${d.id}\">${d.name} (#${d.id})</option>`).join('');\n");
      out.write("\n");
      out.write("    if (mode === 'edit' && id !== null) {\n");
      out.write("        title.innerText = 'Edit Activity';\n");
      out.write("        const act = allActivities.find(a => a.id === id);\n");
      out.write("        if (act) {\n");
