      out.write("function getPlans() {\n");
      out.write("    let raw = localStorage.getItem(LS_PLANS_KEY);\n");
      out.write("    if (!raw) {\n");
      out.write("        localStorage.setItem(LS_PLANS_KEY, JSON.stringify(initialPlans));\n");
      out.write("        return initialPlans;\n");
      out.write("    }\n");
      out.write("    return JSON.parse(raw);\n");
      out.write("}\n");
