      out.write("function loadPlans() {\n");
      out.write("    let plans = getPlans();\n");
      out.write("    document.getElementById('statPlans').innerText = plans.length;\n");
      out.write("    \n");
      out.write("    // Sort and Search Filtering\n");
      out.write("    const query = document.getElementById('searchPlans') ? document.getElementById('searchPlans').value.toLowerCase() : '';\n");
      out.write("    const priceRange = document.getElementById('filterPriceRange') ? document.getElementById('filterPriceRange').value : '';\n");
      out.write("    const sort = document.getElementById('sortPlans') ? document.getElementById('sortPlans').value : 'newest';\n");
      out.write("    \n");
      out.write("    if (query) {\n");
      out.write("        plans = plans.filter(p => p.title.toLowerCase().includes(query) || p.location.toLowerCase().includes(query) || p.price.toString().toLowerCase().includes(query));\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    if (priceRange) {\n");
      out.write("        plans = plans.filter(p => {\n");
      out.write("            const numPrice = parseFloat(p.price.replace(/[^0-9.]/g,''));\n");
      out.write("            if (priceRange === 'under1000') return numPrice < 1000;\n");
      out.write("            if (priceRange === '1000to2000') return numPrice >= 1000 && numPrice <= 2000;\n");
      out.write("            if (priceRange === 'over2000') return numPrice > 2000;\n");
      out.write("            return true;\n");
      out.write("        });\n");
      out.write("    }\n");
      out.write("    \n");
      out.write("    if (sort === 'price_asc') {\n");
      out.write("        plans.sort((a,b) => parseFloat(a.price.replace(/[^0-9.]/g,'')) - parseFloat(b.price.replace(/[^0-9.]/g,'')));\n");
      out.write("    } else if (sort === 'price_desc') {\n");
      out.write("        plans.sort((a,b) => parseFloat(b.price.replace(/[^0-9.]/g,'')) - parseFloat(a.price.replace(/[^0-9.]/g,'')));\n");
      out.write("    } else {\n");
      out.write("        plans.sort((a,b) => b.id - a.id); // Newest First (Sort by ID desc)\n");
      out.write("    }\n");
      out.write("    \n");
      out.write("    const tbody = document.getElementById('plansTableBody');\n");
      out.write("    if (plans.length === 0) {\n");
      out.write("        tbody.innerHTML = '<tr><td colspan=\"6\" style=\"text-align:center; padding: 30px; color:#888;\">No plans found matching criteria.</td></tr>';\n");
      out.write("        return;\n");
