      out.write("            <td style=\"font-weight:700; width:30%;\">\n");
      out.write("                <div class=\"editable-cell\" onclick=\"enableInlineEdit(this, ${p.id}, 'title')\">${p.title}</div>\n");
      out.write("            </td>\n");
      out.write("            <td>\n");
      out.write("                <div class=\"editable-cell\" onclick=\"enableInlineEdit(this, ${p.id}, 'location')\">${p.location}</div>\n");
      out.write("            </td>\n");
      out.write("            <td>\n");
      out.write("                <div class=\"editable-cell\" onclick=\"enableInlineEdit(this, ${p.id}, 'duration')\">${p.duration}</div>\n");
      out.write("            </td>\n");
      out.write("            <td class=\"text-primary font-bold\">\n");
      out.write("                <div class=\"editable-cell\" onclick=\"enableInlineEdit(this, ${p.id}, 'price')\">${p.price}</div>\n");
      out.write("            </td>\n");
      out.write("            <td style=\"text-align: right; white-space: nowrap;\">\n");
      out.write("                <button type=\"button\" class=\"action-btn btn-edit\" onclick=\"editPlan(${p.id})\">Edit</button>\n");
      out.write("                <button type=\"button\" class=\"action-btn btn-delete\" onclick=\"deletePlan(${p.id})\">Delete</button>\n");
