      out.write("function enableInlineEdit(cell, id, field) {\n");
      out.write("    if (cell.querySelector('input')) return;\n");
      out.write("    var currentValue = cell.innerText.trim();\n");
      out.write("    var inp = document.createElement('input');\n");
      out.write("    inp.type = 'text';\n");
      out.write("    inp.className = 'editable-input';\n");
      out.write("    inp.value = currentValue;\n");
      out.write("    inp.addEventListener('blur', function() { saveInlineEdit(inp, id, field, currentValue); });\n");
      out.write("    inp.addEventListener('keypress', function(e) { if (e.key === 'Enter') inp.blur(); });\n");
      out.write("    cell.innerHTML = '';\n");
      out.write("    cell.appendChild(inp);\n");
      out.write("    inp.focus();\n");
      out.write("    inp.select();\n");
      out.write("}\n");
      out.write("\n");
      out.write("function saveInlineEdit(input, id, field, oldValue) {\n");
      out.write("    const newValue = input.value.trim();\n");
      out.write("    if (newValue && newValue !== oldValue) {\n");
      out.write("        const plans = getPlans();\n");
      out.write("        const index = plans.findIndex(p => p.id === id);\n");
      out.write("        if (index > -1) {\n");
      out.write("            plans[index][field] = newValue;\n");
      out.write("            savePlans(plans);\n");
      out.write("            typeof showToast === 'function' ? showToast('Row updated quickly via inline edit.', 'success') : false;\n");
      out.write("        }\n");
      out.write("    }\n");
      out.write("    loadPlans();\n");
      out.write("}\n");
