      out.write("/* =========================================================\n");
      out.write("   CONTENT MANAGEMENT LOGIC\n");
      out.write("========================================================= */\n");
      out.write("const LS_CONTENT_KEY = 'voyastra_admin_content';\n");
      out.write("\n");
      out.write("const initialContent = [\n");
      out.write("    { id: 1, section: 'Trending Places', title: 'Santorini Escapes', image: 'https://images.unsplash.com/photo-1613395877344-13d4a8e0d49e?auto=format&fit=crop&w=600&q=80', price: 'From $1,200', tags: 'Beach, Romantic' },\n");
      out.write("    { id: 2, section: 'Top Travel Plans', title: 'Kyoto Autumn', image: 'https://images.unsplash.com/photo-1493976040374-85c8e12f0c0e?auto=format&fit=crop&w=600&q=80', price: '$2,300', tags: 'Culture, Nature' },\n");
      out.write("    { id: 3, section: 'Featured Cards', title: 'Swiss Alps Skiing', image: 'https://images.unsplash.com/photo-1530122037265-a5f1f91d3b99?auto=format&fit=crop&w=600&q=80', price: 'From $900', tags: 'Adventure, Snow' }\n");
      out.write("];\n");
      out.write("\n");
      out.write("function getContent() {\n");
      out.write("    let raw = localStorage.getItem(LS_CONTENT_KEY);\n");
