      out.write("function editContent(id) { openContentModal(id); }\n");
      out.write("\n");
      out.write("/* =========================================================\n");
      out.write("   IMAGE PREVIEW\n");
      out.write("========================================================= */\n");
      out.write("function previewImg(inputId, previewId) {\n");
      out.write("    var url = document.getElementById(inputId).value.trim();\n");
      out.write("    var img = document.getElementById(previewId);\n");
      out.write("    if (url) {\n");
      out.write("        img.src = url;\n");
      out.write("        img.style.display = 'block';\n");
      out.write("        img.onerror = function() { img.style.display = 'none'; };\n");
      out.write("    } else {\n");
      out.write("        img.style.display = 'none';\n");
      out.write("    }\n");
      out.write("}\n");
      out.write("\n");
      out.write("// Bind drag and drop file upload mockup\n");
      out.write("setTimeout(() => {\n");
      out.write("    const fileInput = document.getElementById('destImageFile');\n");
      out.write("    const urlInput = document.getElementById('destImage');\n");
      out.write("    const box = document.getElementById('destImageUploadBox');\n");
      out.write("    \n");
      out.write("    if (fileInput && urlInput) {\n");
      out.write("        fileInput.addEventListener('change', function(e) {\n");
      out.write("            if(e.target.files && e.target.files[0]) {\n");
      out.write("                const reader = new FileReader();\n");
      out.write("                reader.onload = function(e) {\n");
      out.write("                    urlInput.value = e.target.result;\n");
      out.write("                    previewImg('destImage', 'destImagePreview');\n");
      out.write("                    showToast('Local image ready for upload mockup.', 'success');\n");
      out.write("                }\n");
      out.write("                reader.readAsDataURL(e.target.files[0]);\n");
      out.write("            }\n");
      out.write("        });\n");
      out.write("        \n");
      out.write("        box.addEventListener('dragover', () => box.style.borderColor = '#4f46e5');\n");
      out.write("        box.addEventListener('dragleave', () => box.style.borderColor = '');\n");
      out.write("        box.addEventListener('drop', () => box.style.borderColor = '');\n");
      out.write("    }\n");
      out.write("}, 500);\n");
      out.write("\n");
      out.write("/* =========================================================\n");
      out.write("   DASHBOARD ANALYTICS\n");
      out.write("========================================================= */\n");
      out.write("function loadAnalytics() {\n");
      out.write("    // 1. Fetch real-time statistics from DB via AdminAnalyticsServlet\n");
      out.write("    fetch('admin/stats')\n");
      out.write("        .then(response => response.json())\n");
      out.write("        .then(data => {\n");
      out.write("            // Update Dashboard Overview Cards\n");
      out.write("            if (document.getElementById('statUsers')) document.getElementById('statUsers').innerText = data.users.toLocaleString();\n");
      out.write("            if (document.getElementById('statBookings')) document.getElementById('statBookings').innerText = data.bookings.toLocaleString();\n");
      out.write("            if (document.getElementById('statPlans')) document.getElementById('statPlans').innerText = data.plans.toLocaleString();\n");
      out.write("            if (document.getElementById('statDests')) document.getElementById('statDests').innerText = data.destinations.toLocaleString();\n");
      out.write("            \n");
      out.write("            if (document.getElementById('statRevenue')) {\n");
      out.write("                const formatter = new Intl.NumberFormat('en-US', {\n");
      out.write("                    style: 'currency',\n");
      out.write("                    currency: 'USD',\n");
      out.write("                });\n");
      out.write("                document.getElementById('statRevenue').innerText = formatter.format(data.revenue);\n");
      out.write("            }\n");
      out.write("        })\n");
      out.write("        .catch(err => {\n");
      out.write("            console.error('Analytics Error:', err);\n");
      out.write("            // Fallback UI or silent fail\n");
      out.write("        });\n");
      out.write("\n");
      out.write("    // 2. Existing chart/activity logic (Optional: migrate to DB as well)\n");
      out.write("    var dests = getDests();\n");
      out.write("    var chart = document.getElementById('destBarChart');\n");
      out.write("    if (chart) {\n");
      out.write("        var colors = ['#4f46e5','#06b6d4','#fbbf24','#10b981','#ef4444'];\n");
      out.write("        chart.innerHTML = dests.slice(0,5).map(function(d, i) {\n");
      out.write("            var pct = Math.max(20, Math.round(Math.random() * 60 + 30));\n");
      out.write("            return '<div>'\n");
      out.write("                + '<div style=\"display:flex; justify-content:space-between; margin-bottom:5px; font-size:0.82rem;\">'\n");
      out.write("                + '<span>' + d.name + '</span><span style=\"color:' + colors[i % colors.length] + '; font-weight:600;\">' + pct + '%</span>'\n");
      out.write("                + '</div>'\n");
      out.write("                + '<div style=\"background:var(--color-border); border-radius:8px; overflow:hidden; height:8px;\">'\n");
      out.write("                + '<div style=\"width:' + pct + '%; height:8px; background:' + colors[i % colors.length] + '; border-radius:8px; transition: width 0.6s ease;\"></div>'\n");
      out.write("                + '</div></div>';\n");
      out.write("        }).join('');\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    var revs = getReviews();\n");
      out.write("    if (revs.length > 0) {\n");
      out.write("        var approved = revs.filter(function(r) { return r.approved; }).length;\n");
      out.write("        var approvedPct = Math.round((approved / revs.length) * 100);\n");
      out.write("        var pendingPct = 100 - approvedPct;\n");
      out.write("        if (document.getElementById('approvedPct')) document.getElementById('approvedPct').innerText = approvedPct + '%';\n");
      out.write("        if (document.getElementById('pendingPct')) document.getElementById('pendingPct').innerText = pendingPct + '%';\n");
      out.write("        if (document.getElementById('approvedBar')) document.getElementById('approvedBar').style.width = approvedPct + '%';\n");
      out.write("        if (document.getElementById('pendingBar')) document.getElementById('pendingBar').style.width = pendingPct + '%';\n");
      out.write("    }\n");
      out.write("}\n");
      out.write("\n");
      out.write("/* =========================================================\n");
      out.write("   SETTINGS PANEL\n");
      out.write("========================================================= */\n");
      out.write("function applySettingsTheme(isDark) {\n");
      out.write("    var slider = document.getElementById('themeSlider');\n");
      out.write("    if (isDark) {\n");
      out.write("        document.documentElement.setAttribute('data-theme', 'dark');\n");
      out.write("        if (slider) slider.style.background = '#4f46e5';\n");
      out.write("    } else {\n");
      out.write("        document.documentElement.setAttribute('data-theme', 'light');\n");
      out.write("        if (slider) slider.style.background = '#ccc';\n");
      out.write("    }\n");
      out.write("    localStorage.setItem('voyastra_admin_theme', isDark ? 'dark' : 'light');\n");
      out.write("    showToast('Theme switched to ' + (isDark ? 'Dark' : 'Light') + ' mode.', 'success');\n");
      out.write("}\n");
      out.write("\n");
      out.write("function initSettings() {\n");
      out.write("    var saved = localStorage.getItem('voyastra_admin_theme');\n");
      out.write("    var isDark = saved === 'dark';\n");
      out.write("    var cb = document.getElementById('settingsTheme');\n");
      out.write("    if (cb) cb.checked = isDark;\n");
      out.write("    var slider = document.getElementById('themeSlider');\n");
      out.write("    if (slider) slider.style.background = isDark ? '#4f46e5' : '#ccc';\n");
      out.write("}\n");
      out.write("\n");
      out.write("function resetAllData() {\n");
      out.write("    localStorage.removeItem('voyastra_admin_plans');\n");
      out.write("    localStorage.removeItem('voyastra_admin_dests');\n");
      out.write("    localStorage.removeItem('voyastra_admin_reviews');\n");
      out.write("    localStorage.removeItem('voyastra_admin_content');\n");
      out.write("    loadPlans(); loadDests(); loadReviews(); loadContent(); loadAnalytics();\n");
      out.write("    showToast('All data reset to factory defaults.', 'warning');\n");
      out.write("}\n");
      out.write("\n");
      out.write("/* =========================================================\n");
      out.write("   USER MANAGEMENT LOGIC\n");
      out.write("========================================================= */\n");
      out.write("const LS_USERS_KEY = 'voyastra_admin_users';\n");
      out.write("const initialUsers = [\n");
      out.write("    { id: 1, name: 'Alice Jenkins', email: 'alice@example.com', role: 'User', status: 'Active' },\n");
      out.write("    { id: 2, name: 'Bob Smith', email: 'bob@example.com', role: 'Premium', status: 'Active' },\n");
      out.write("    { id: 3, name: 'Charlie Doe', email: 'charlie@example.com', role: 'User', status: 'Suspended' }\n");
      out.write("];\n");
      out.write("\n");
      out.write("function getUsers() {\n");
      out.write("    let raw = localStorage.getItem(LS_USERS_KEY);\n");
      out.write("    if (!raw) { localStorage.setItem(LS_USERS_KEY, JSON.stringify(initialUsers)); return initialUsers; }\n");
      out.write("    return JSON.parse(raw);\n");
      out.write("}\n");
      out.write("function saveUsers(users) { localStorage.setItem(LS_USERS_KEY, JSON.stringify(users)); }\n");
      out.write("\n");
      out.write("function loadUsers() {\n");
      out.write("    let users = getUsers();\n");
      out.write("    const query = document.getElementById('searchUsers') ? document.getElementById('searchUsers').value.toLowerCase() : '';\n");
      out.write("    if (query) users = users.filter(u => u.name.toLowerCase().includes(query) || u.email.toLowerCase().includes(query));\n");
      out.write("    \n");
      out.write("    const tbody = document.getElementById('usersTableBody');\n");
      out.write("    if (!tbody) return;\n");
      out.write("    if (users.length === 0) {\n");
      out.write("        tbody.innerHTML = '<tr><td colspan=\"4\" class=\"empty-state\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"12\" cy=\"12\" r=\"10\"/><line x1=\"12\" y1=\"8\" x2=\"12\" y2=\"12\"/><line x1=\"12\" y1=\"16\" x2=\"12.01\" y2=\"16\"/></svg><br>No registered users found.</td></tr>';\n");
      out.write("        return;\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    tbody.innerHTML = users.map(u => `\n");
      out.write("        <tr>\n");
      out.write("            <td style=\"font-weight:600;\">${u.name}</td>\n");
      out.write("            <td style=\"color:var(--text-muted);\">${u.email}</td>\n");
      out.write("            <td><span style=\"padding:4px 8px; border-radius:12px; font-size:0.75rem; background: ${u.role==='Premium'?'rgba(251,191,36,0.1)':'rgba(59,130,246,0.1)'}; color: ${u.role==='Premium'?'#fbbf24':'#3b82f6'};\">${u.role}</span></td>\n");
      out.write("            <td style=\"text-align: right;\">\n");
      out.write("                <button type=\"button\" class=\"action-btn btn-edit\" style=\"margin-right:8px;\" onclick=\"suspendUser(${u.id})\">${u.status==='Suspended' ? 'Unsuspend' : 'Suspend'}</button>\n");
      out.write("                <button type=\"button\" class=\"action-btn btn-delete\" onclick=\"deleteUser(${u.id})\">Delete</button>\n");
      out.write("            </td>\n");
      out.write("        </tr>\n");
      out.write("    `).join('');\n");
      out.write("}\n");
      out.write("\n");
      out.write("function suspendUser(id) {\n");
      out.write("    const users = getUsers();\n");
      out.write("    const u = users.find(x => x.id === id);\n");
      out.write("    if(u) {\n");
      out.write("        u.status = u.status === 'Suspended' ? 'Active' : 'Suspended';\n");
      out.write("        saveUsers(users);\n");
      out.write("        logActivity(`Admin ${u.status === 'Suspended' ? 'suspended' : 'unsuspended'} user ${u.name}`);\n");
      out.write("        loadUsers();\n");
      out.write("    }\n");
      out.write("}\n");
      out.write("function deleteUser(id) {\n");
      out.write("    advancedConfirm('Permanently delete this user?', () => {\n");
      out.write("        saveUsers(getUsers().filter(u => u.id !== id));\n");
      out.write("        logActivity(`Admin deleted a user account`);\n");
      out.write("        loadUsers();\n");
      out.write("    });\n");
      out.write("}\n");
      out.write("\n");
      out.write("/* =========================================================\n");
      out.write("   ACTIVITY LOG LOGIC\n");
      out.write("========================================================= */\n");
      out.write("const LS_ACTIVITY_KEY = 'voyastra_admin_activity';\n");
      out.write("const initialActivity = [\n");
      out.write("    { id: 1, text: 'System initialized successfully', time: new Date().toISOString() }\n");
      out.write("];\n");
      out.write("\n");
      out.write("function getActivity() {\n");
      out.write("    let raw = localStorage.getItem(LS_ACTIVITY_KEY);\n");
      out.write("    if (!raw) { localStorage.setItem(LS_ACTIVITY_KEY, JSON.stringify(initialActivity)); return initialActivity; }\n");
      out.write("    return JSON.parse(raw);\n");
      out.write("}\n");
      out.write("function saveActivity(acts) { localStorage.setItem(LS_ACTIVITY_KEY, JSON.stringify(acts)); }\n");
      out.write("\n");
      out.write("function logActivity(text) {\n");
      out.write("    const acts = getActivity();\n");
      out.write("    acts.unshift({ id: Date.now(), text, time: new Date().toISOString() });\n");
      out.write("    if(acts.length > 50) acts.pop();\n");
      out.write("    saveActivity(acts);\n");
      out.write("    loadActivityLog();\n");
      out.write("}\n");
      out.write("\n");
      out.write("function loadActivityLog() {\n");
      out.write("    const box = document.getElementById('activityTimelineBox');\n");
      out.write("    if (!box) return;\n");
      out.write("    \n");
      out.write("    fetch('admin/logs?format=json')\n");
      out.write("        .then(response => response.json())\n");
      out.write("        .then(logs => {\n");
      out.write("            if (!logs || logs.length === 0) {\n");
      out.write("                box.innerHTML = '<div style=\"text-align:center; padding: 40px; color:#888;\">No system activity recorded yet.</div>';\n");
      out.write("                return;\n");
      out.write("            }\n");
      out.write("            \n");
      out.write("            box.innerHTML = `<div class=\"activity-timeline\">` + logs.map(log => `\n");
      out.write("                <div class=\"activity-item\">\n");
      out.write("                    <div class=\"activity-dot\" style=\"background: ${log.color}\"></div>\n");
      out.write("                    <div class=\"activity-content\">\n");
      out.write("                        <div class=\"activity-header\">\n");
      out.write("                            <span class=\"activity-badge\" style=\"background: ${log.color}22; color: ${log.color}\">${log.action}</span>\n");
      out.write("                            <span class=\"activity-time\">${log.timestamp}</span>\n");
      out.write("                        </div>\n");
      out.write("                        <div class=\"activity-msg\">\n");
      out.write("                            <span class=\"activity-admin\">@${log.adminUsername}</span> ${log.details}\n");
      out.write("                        </div>\n");
      out.write("                    </div>\n");
      out.write("                </div>\n");
      out.write("            `).join('') + `</div>`;\n");
      out.write("        })\n");
      out.write("        .catch(err => {\n");
      out.write("            console.error('Failed to load logs:', err);\n");
      out.write("            box.innerHTML = '<div style=\"color:var(--color-primary); padding:20px; text-align:center;\">Failed to connect to activity service.</div>';\n");
      out.write("        });\n");
      out.write("}\n");
      out.write("\n");
      out.write("function loadRecentActivityOverview() {\n");
      out.write("    const list = document.getElementById('recentActivityList');\n");
      out.write("    if (!list) return;\n");
      out.write("    \n");
      out.write("    fetch('admin/logs?limit=5&format=json')\n");
      out.write("        .then(response => response.json())\n");
      out.write("        .then(logs => {\n");
      out.write("            if (!logs || logs.length === 0) {\n");
      out.write("                list.innerHTML = '<div style=\"padding:40px; text-align:center; color:var(--text-muted);\">No recent actions found.</div>';\n");
      out.write("                return;\n");
      out.write("            }\n");
      out.write("            \n");
      out.write("            list.innerHTML = logs.map(log => `\n");
      out.write("                <div class=\"recent-log-row\">\n");
      out.write("                    <div class=\"recent-log-dot\" style=\"background: ${log.color}\"></div>\n");
      out.write("                    <div class=\"recent-log-info\">\n");
      out.write("                        <div class=\"recent-log-title\">@${log.adminUsername} ${log.action}d <span style=\"color:var(--text-muted); font-weight:400\">${log.targetTable}</span></div>\n");
      out.write("                        <div class=\"recent-log-sub\">${log.details}</div>\n");
      out.write("                    </div>\n");
      out.write("                    <div style=\"font-size:0.75rem; color:var(--text-muted);\">${log.timestamp.split('T')[1].substring(0,5)}</div>\n");
      out.write("                </div>\n");
      out.write("            `).join('');\n");
      out.write("        });\n");
      out.write("}\n");
      out.write("\n");
      out.write("/* =========================================================\n");
      out.write("   DRAG AND DROP FOR CONTENT MANAGEMENT\n");
      out.write("========================================================= */\n");
      out.write("function initContentDragDrop() {\n");
      out.write("    const cards = document.querySelectorAll('#contentGrid .stat-card');\n");
      out.write("    let draggedCard = null;\n");
      out.write("\n");
      out.write("    cards.forEach(card => {\n");
      out.write("        card.setAttribute('draggable', true);\n");
      out.write("        card.classList.add('draggable-card');\n");
      out.write("\n");
      out.write("        card.addEventListener('dragstart', function(e) {\n");
      out.write("            draggedCard = card;\n");
      out.write("            setTimeout(() => card.classList.add('dragging'), 0);\n");
      out.write("            e.dataTransfer.effectAllowed = 'move';\n");
      out.write("        });\n");
      out.write("\n");
      out.write("        card.addEventListener('dragend', function() {\n");
      out.write("            draggedCard.classList.remove('dragging');\n");
      out.write("            draggedCard = null;\n");
      out.write("            document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));\n");
      out.write("            \n");
      out.write("            // Auto update order based on DOM position\n");
      out.write("            const newOrderIds = Array.from(document.querySelectorAll('#contentGrid .stat-card')).map(c => parseInt(c.getAttribute('data-id')));\n");
      out.write("            const allContent = getContent();\n");
      out.write("            const reorderedContent = newOrderIds.map(id => allContent.find(c => c.id === id)).filter(Boolean);\n");
      out.write("            if (reorderedContent.length === allContent.length) {\n");
      out.write("                saveContent(reorderedContent);\n");
      out.write("                logActivity('Admin reordered content cards');\n");
      out.write("                typeof showToast === 'function' && showToast('Content order saved automatically', 'success');\n");
      out.write("            }\n");
      out.write("        });\n");
      out.write("\n");
      out.write("        card.addEventListener('dragover', function(e) {\n");
      out.write("            e.preventDefault();\n");
      out.write("            e.dataTransfer.dropEffect = 'move';\n");
      out.write("            if (card !== draggedCard) card.classList.add('drag-over');\n");
      out.write("        });\n");
      out.write("\n");
      out.write("        card.addEventListener('dragleave', function() {\n");
      out.write("            card.classList.remove('drag-over');\n");
      out.write("        });\n");
      out.write("\n");
      out.write("        card.addEventListener('drop', function(e) {\n");
      out.write("            e.preventDefault();\n");
      out.write("            if (card !== draggedCard && draggedCard) {\n");
      out.write("                const grid = document.getElementById('contentGrid');\n");
      out.write("                const dragIndex = Array.from(grid.children).indexOf(draggedCard);\n");
      out.write("                const dropIndex = Array.from(grid.children).indexOf(card);\n");
      out.write("                if (dragIndex < dropIndex) {\n");
      out.write("                    card.after(draggedCard);\n");
      out.write("                } else {\n");
      out.write("                    card.before(draggedCard);\n");
      out.write("                }\n");
      out.write("            }\n");
      out.write("            card.classList.remove('drag-over');\n");
      out.write("        });\n");
      out.write("    });\n");
      out.write("}\n");
      out.write("\n");
      out.write("function overrideLoadContentWithDataId() {\n");
      out.write("    // Modify existing loadContent temporarily to add data-id and call initContentDragDrop\n");
      out.write("    const originalLoadContent = window.loadContent;\n");
      out.write("    window.loadContent = function() {\n");
      out.write("        originalLoadContent.call(window);\n");
      out.write("        // Inject data-id into the generated cards\n");
      out.write("        const data = getContent();\n");
      out.write("        const grid = document.getElementById('contentGrid');\n");
      out.write("        if(grid && data.length > 0) {\n");
      out.write("            const cards = grid.children;\n");
      out.write("            for(let i=0; i<data.length; i++){\n");
      out.write("                if(cards[i]) cards[i].setAttribute('data-id', data[i].id);\n");
      out.write("            }\n");
      out.write("        }\n");
      out.write("        initContentDragDrop();\n");
      out.write("    };\n");
      out.write("}\n");
      out.write("// Automatically hook the override\n");
      out.write("overrideLoadContentWithDataId();\n");
      out.write("\n");
      out.write("/* =========================================================\n");
      out.write("   GLOBAL SEARCH LOGIC\n");
      out.write("========================================================= */\n");
      out.write("function setupGlobalSearch() {\n");
      out.write("    const input = document.getElementById('globalAdminSearch');\n");
      out.write("    const dropdown = document.getElementById('globalSearchResults');\n");
      out.write("    if (!input || !dropdown) return;\n");
      out.write("    \n");
      out.write("    input.addEventListener('input', function(e) {\n");
      out.write("        const query = e.target.value.toLowerCase().trim();\n");
      out.write("        if (!query) { dropdown.classList.remove('active'); return; }\n");
      out.write("        \n");
      out.write("        let resultsHTML = '';\n");
      out.write("        \n");
      out.write("        getPlans().forEach(p => {\n");
      out.write("            if (p.title.toLowerCase().includes(query) || p.location.toLowerCase().includes(query)) {\n");
      out.write("                resultsHTML += `<div class=\"search-result-item\" onclick=\"jumpToSection('managePlans', ${p.id})\">\n");
      out.write("                    <strong>Plan:</strong> ${p.title} <span class=\"text-muted\" style=\"font-size:0.8rem\">(${p.location})</span>\n");
      out.write("                </div>`;\n");
      out.write("            }\n");
      out.write("        });\n");
      out.write("        \n");
      out.write("        getDests().forEach(d => {\n");
      out.write("            if (d.name.toLowerCase().includes(query) || d.location.toLowerCase().includes(query)) {\n");
      out.write("                resultsHTML += `<div class=\"search-result-item\" onclick=\"jumpToSection('manageDestinations', ${d.id})\">\n");
      out.write("                    <strong>Dest:</strong> ${d.name} <span class=\"text-muted\" style=\"font-size:0.8rem\">(${d.location})</span>\n");
      out.write("                </div>`;\n");
      out.write("            }\n");
      out.write("        });\n");
      out.write("        \n");
      out.write("        getUsers().forEach(u => {\n");
      out.write("            if (u.name.toLowerCase().includes(query) || u.email.toLowerCase().includes(query)) {\n");
      out.write("                resultsHTML += `<div class=\"search-result-item\" onclick=\"jumpToSection('manageUsers', ${u.id})\">\n");
